// Validate and normalize AI agent output
const response = $input.first().json;

// Extract the agent output
let aiData = response.output || response.text || response;

// Parse if it's a JSON string
if (typeof aiData === 'string') {
  try {
    aiData = JSON.parse(aiData);
  } catch (e) {
    throw new Error('AI output is not valid JSON: ' + e.message);
  }
}

// Validate required fields per schema
const required = ['answer', 'sources', 'confidence', 'summary'];
for (const field of required) {
  if (!(field in aiData)) {
    throw new Error(`Required field '${field}' missing from AI output`);
  }
}

// Type validation
if (typeof aiData.answer !== 'string' || aiData.answer.length < 20) {
  throw new Error('Answer must be a string with at least 20 characters');
}

if (!Array.isArray(aiData.sources) || aiData.sources.length === 0) {
  throw new Error('Sources must be a non-empty array');
}

if (typeof aiData.confidence !== 'number' || aiData.confidence < 0 || aiData.confidence > 1) {
  throw new Error('Confidence must be a number between 0 and 1');
}

if (typeof aiData.summary !== 'string' || aiData.summary.length < 10) {
  throw new Error('Summary must be a string with at least 10 characters');
}

// Optional field validation
if (aiData.key_points && !Array.isArray(aiData.key_points)) {
  throw new Error('key_points must be an array if provided');
}

// Return validated data
return aiData;

// Enrich validated output with execution metadata
const validated = $input.first().json;

return {
  success: true,
  processed: true,
  data: {
    answer: validated.answer,
    summary: validated.summary,
    sources: validated.sources,
    confidence: validated.confidence,
    key_points: validated.key_points || [],
    metadata: {
      word_count: validated.answer.split(' ').length,
      source_count: validated.sources.length,
      has_key_points: Boolean(validated.key_points),
      quality_score: validated.confidence,
      timestamp: new Date().toISOString(),
      execution_id: $execution.id,
      workflow_id: $workflow.id,
      workflow_name: $workflow.name
    }
  }
};

